<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Falling Sand</title>
<style>
  *{margin:0;padding:0;box-sizing:border-box}
  body{
    background:#0d0d1a;
    color:#e0e0e0;
    font-family:'Segoe UI',Tahoma,Geneva,Verdana,sans-serif;
    display:flex;justify-content:center;align-items:center;
    min-height:100vh;flex-direction:column;gap:16px;
  }
  #sand{
    border:2px solid #2a2a3e;border-radius:8px;cursor:crosshair;
    image-rendering:pixelated;
    box-shadow:0 0 40px rgba(0,0,0,.6);
  }
  #controls{display:flex;gap:8px;flex-wrap:wrap;justify-content:center}
  button{
    padding:10px 20px;border:none;border-radius:6px;font-size:13px;
    font-weight:600;cursor:pointer;transition:all .15s ease;
    text-transform:uppercase;letter-spacing:.5px;
  }
  button:hover{transform:translateY(-2px);box-shadow:0 4px 15px rgba(0,0,0,.4)}
  button:active{transform:translateY(0);box-shadow:none}
  button.active{box-shadow:0 0 0 3px rgba(255,255,255,.25),0 2px 8px rgba(0,0,0,.3)}
  #mat-sand{background:#e6c44d;color:#2a2000}
  #mat-water{background:#4a90d9;color:#fff}
  #mat-wall{background:#666677;color:#fff}
  #mat-acid{background:#50c878;color:#1a3d2a}
  #mat-empty{background:#444455;color:#fff}
  #clear{background:#d94a4a;color:#fff}
</style>
</head>
<body>
<canvas id="sand"></canvas>
<div id="controls">
  <button id="mat-sand" class="active">Sand</button>
  <button id="mat-water">Water</button>
  <button id="mat-wall">Wall</button>
  <button id="mat-acid">Acid</button>
  <button id="mat-empty">Eraser</button>
  <button id="clear">Clear</button>
</div>
<script>
(function(){
  const W=100, H=100, CELL=5;
  const canvas=document.getElementById('sand');
  const ctx=canvas.getContext('2d');
  canvas.width=W*CELL; canvas.height=H*CELL;

  const EMPTY=0,SAND=1,WATER=2,WALL=3,ACID=4;
  const NAMES=['empty','sand','water','wall','acid'];
  const FROM={empty:0,sand:1,water:2,wall:3,acid:4};

  let grid=new Uint8Array(W*H);

  // Seeded PRNG for deterministic ticks
  let _rng=12345;
  function rng(){_rng=(_rng*1103515245+12345)&0x7fffffff;return _rng/0x7fffffff}

  function tick(){
    const moved=new Uint8Array(W*H);
    for(let y=H-1;y>=0;y--){
      for(let x=0;x<W;x++){
        const i=y*W+x;
        if(moved[i])continue;
        const m=grid[i];
        if(m===EMPTY||m===WALL)continue;

        if(m===SAND){
          // fall straight
          if(y+1<H){
            const b=(y+1)*W+x, bm=grid[b];
            if(bm===EMPTY){grid[b]=SAND;grid[i]=EMPTY;moved[b]=1;continue}
            if(bm===WATER||bm===ACID){grid[b]=SAND;grid[i]=bm;moved[b]=1;continue}
          }
          // diagonal
          const dir=rng()<.5?-1:1;
          for(const d of[dir,-dir]){
            const dx=x+d;
            if(dx>=0&&dx<W&&y+1<H){
              const di=(y+1)*W+dx, dm=grid[di];
              if(dm===EMPTY){grid[di]=SAND;grid[i]=EMPTY;moved[di]=1;break}
              if(dm===WATER||dm===ACID){grid[di]=SAND;grid[i]=dm;moved[di]=1;break}
            }
          }
        } else if(m===WATER){
          if(y+1<H&&grid[(y+1)*W+x]===EMPTY){
            grid[(y+1)*W+x]=WATER;grid[i]=EMPTY;moved[(y+1)*W+x]=1;continue;
          }
          const dir=rng()<.5?-1:1;
          for(const d of[dir,-dir]){
            const dx=x+d;
            if(dx>=0&&dx<W&&grid[y*W+dx]===EMPTY){
              grid[y*W+dx]=WATER;grid[i]=EMPTY;moved[y*W+dx]=1;break;
            }
          }
        } else if(m===ACID){
          // dissolve sand/wall below or beside
          let dissolved=false;
          if(y+1<H){
            const b=(y+1)*W+x;
            if(grid[b]===SAND||grid[b]===WALL){grid[b]=EMPTY;dissolved=true}
          }
          if(!dissolved){
            for(const d of[-1,1]){
              const dx=x+d;
              if(dx>=0&&dx<W){
                const s=y*W+dx;
                if(grid[s]===SAND||grid[s]===WALL){grid[s]=EMPTY;dissolved=true;break}
              }
            }
          }
          // move like water (acid persists)
          if(y+1<H&&grid[(y+1)*W+x]===EMPTY){
            grid[(y+1)*W+x]=ACID;grid[i]=EMPTY;moved[(y+1)*W+x]=1;continue;
          }
          const dir=rng()<.5?-1:1;
          for(const d of[dir,-dir]){
            const dx=x+d;
            if(dx>=0&&dx<W&&grid[y*W+dx]===EMPTY){
              grid[y*W+dx]=ACID;grid[i]=EMPTY;moved[y*W+dx]=1;break;
            }
          }
        }
      }
    }
  }

  function tickN(n){for(let i=0;i<n;i++)tick()}

  function get(x,y){
    if(x<0||x>=W||y<0||y>=H)return'empty';
    return NAMES[grid[y*W+x]];
  }
  function set(x,y,mat){
    if(x<0||x>=W||y<0||y>=H)return;
    if(mat in FROM)grid[y*W+x]=FROM[mat];
  }
  function clearGrid(){grid.fill(EMPTY)}

  window.sim={w:W,h:H,tick:tickN,get,set,clear:clearGrid};

  // Rendering
  const imgData=ctx.createImageData(W*CELL,H*CELL);
  const _data=imgData.data;

  // Precompute color lookup for speed
  const COLORS=[
    [26,26,46],   // empty
    [230,196,77], // sand
    [74,144,217], // water
    [100,100,120],// wall
    [80,200,120]  // acid
  ];

  function render(){
    for(let y=0;y<H;y++){
      for(let x=0;x<W;x++){
        const m=grid[y*W+x];
        const c=COLORS[m]||COLORS[0];
        let r=c[0],g=c[1],b=c[2];
        // slight variation for sand & water
        if(m===SAND){const v=((x*7+y*13)%16)-8;r+=v;g+=v;b+=v}
        if(m===WATER){const v=((x*3+y*11)%12)-6;r+=v;g+=v;b+=v}
        // clamp
        r=Math.max(0,Math.min(255,r));
        g=Math.max(0,Math.min(255,g));
        b=Math.max(0,Math.min(255,b));
        const py0=y*CELL, px0=x*CELL;
        for(let cy=0;cy<CELL;cy++){
          const rowOff=(py0+cy)*W*CELL*4;
          for(let cx=0;cx<CELL;cx++){
            const p=rowOff+(px0+cx)*4;
            _data[p]=r;_data[p+1]=g;_data[p+2]=b;_data[p+3]=255;
          }
        }
      }
    }
    ctx.putImageData(imgData,0,0);
  }

  // Animation
  function animate(){tick();render();requestAnimationFrame(animate)}
  requestAnimationFrame(animate);

  // Painting
  let selMat='sand', painting=false;

  function gridPos(e){
    const r=canvas.getBoundingClientRect();
    const sx=canvas.width/r.width, sy=canvas.height/r.height;
    return{x:Math.floor((e.clientX-r.left)*sx/CELL),y:Math.floor((e.clientY-r.top)*sy/CELL)};
  }

  function paint(x,y){
    const bs=2, mat=FROM[selMat];
    for(let dy=-bs;dy<=bs;dy++)for(let dx=-bs;dx<=bs;dx++){
      const px=x+dx,py=y+dy;
      if(px>=0&&px<W&&py>=0&&py<H)grid[py*W+px]=mat;
    }
  }

  canvas.addEventListener('mousedown',e=>{painting=true;const p=gridPos(e);paint(p.x,p.y)});
  canvas.addEventListener('mousemove',e=>{if(painting){const p=gridPos(e);paint(p.x,p.y)}});
  canvas.addEventListener('mouseup',()=>painting=false);
  canvas.addEventListener('mouseleave',()=>painting=false);

  // Buttons
  document.querySelectorAll('#mat-sand,#mat-water,#mat-wall,#mat-acid,#mat-empty').forEach(btn=>{
    btn.addEventListener('click',()=>{
      document.querySelectorAll('#controls button').forEach(b=>b.classList.remove('active'));
      btn.classList.add('active');
      selMat=btn.id.replace('mat-','');
    });
  });

  document.getElementById('clear').addEventListener('click',()=>{clearGrid();render()});
})();
</script>
</body>
</html>
